import groovy.json.JsonSlurper

def response = testRunner.testCase.testSteps["GET /api/coins (USD)"].testRequest.response.responseContent

assert response != null && response.trim().length() > 0 : "Response body is empty"

def parser = new JsonSlurper()
def coins = parser.parseText(response)

// Must be a list
assert coins instanceof List : "Response should be a JSON array"

// Must have at least 1 coin
assert coins.size() > 0 : "Response array should not be empty"

log.info "✅ Response is a valid JSON array with ${coins.size()} coins"

// Validate each coin has required fields
def requiredFields = ["id", "symbol", "name", "current_price", "market_cap",
                      "price_change_percentage_24h", "high_24h", "low_24h"]

coins.each { coin ->
  requiredFields.each { field ->
    assert coin.containsKey(field) : "Coin '${coin.name}' is missing field: ${field}"
  }

  // Price must be a positive number
  assert coin.current_price != null : "current_price is null for ${coin.name}"
  assert coin.current_price >= 0    : "current_price is negative for ${coin.name}"

  // Market cap must be positive
  assert coin.market_cap != null && coin.market_cap >= 0 : "market_cap invalid for ${coin.name}"
}

log.info "✅ All ${coins.size()} coins have valid required fields"

import groovy.json.JsonSlurper

def parser = new JsonSlurper()

def usdBody = testRunner.testCase.testSteps["GET /api/coins (USD)"] == null
  ? null
  : null  // USD step not in this test case; re-fetch via prior context

def eurResponse = testRunner.testCase.testSteps["GET /api/coins (EUR)"].testRequest.response.responseContent
def gbpResponse = testRunner.testCase.testSteps["GET /api/coins (GBP)"].testRequest.response.responseContent

def eurCoins = parser.parseText(eurResponse)
def gbpCoins = parser.parseText(gbpResponse)

assert eurCoins instanceof List && eurCoins.size() > 0 : "EUR response invalid"
assert gbpCoins instanceof List && gbpCoins.size() > 0 : "GBP response invalid"

// Bitcoin EUR price sanity: must be > 0
def btcEur = eurCoins.find { it.id == "bitcoin" }
def btcGbp = gbpCoins.find { it.id == "bitcoin" }

assert btcEur != null : "Bitcoin not found in EUR response"
assert btcGbp != null : "Bitcoin not found in GBP response"
assert btcEur.current_price > 0 : "Bitcoin EUR price should be positive"
assert btcGbp.current_price > 0 : "Bitcoin GBP price should be positive"

log.info "✅ EUR BTC price: ${btcEur.current_price}"
log.info "✅ GBP BTC price: ${btcGbp.current_price}"

import groovy.json.JsonSlurper

def response = testRunner.testCase.testSteps["GET /api/coins (USD)"].testRequest.response.responseContent
def coins = new JsonSlurper().parseText(response)

// Top coins that should always be in top-20 by market cap
def expectedCoins = ["bitcoin", "ethereum", "tether"]

expectedCoins.each { coinId ->
  def found = coins.find { it.id == coinId }
  assert found != null : "Expected coin '${coinId}' not found in response"
  log.info "✅ Found ${found.name}: \$${found.current_price}"
}

// 24h high must be >= current price
coins.each { coin ->
  if (coin.high_24h != null && coin.current_price != null) {
    assert coin.high_24h >= coin.current_price * 0.9 :
      "${coin.name}: 24h high (${coin.high_24h}) seems inconsistent with price (${coin.current_price})"
  }
  // 24h low must be <= current price (allow 10% tolerance for fast markets)
  if (coin.low_24h != null && coin.current_price != null) {
    assert coin.low_24h <= coin.current_price * 1.1 :
      "${coin.name}: 24h low (${coin.low_24h}) seems inconsistent with price (${coin.current_price})"
  }
}

log.info "✅ Data integrity checks passed for all ${coins.size()} coins"
